    "document.yml.hbs": "name: \"{{title}}\"\n{{#if author}}\nauthor: \"{{author}}\"\n{{/if}}\nyear: {{year}}\n\nfoundation: '@uniweb/data@0.1.0'\nformat: xlsx\n\n# pages/report/ holds one page-folder; everything renders into a single\n# downloadable workbook (xlsx) or report (docx).\nindex: report\n\ncollections:\n  members:\n    path: collections/members\n    # Queryable surface — drives the FilterPanel UI. The framework\n    # decides whether to ship predicates to a backend or evaluate locally\n    # based on `fetcher.supports:`.\n    queryable:\n      department:\n        type: enum\n        label: Department\n        options: [biology, geology]\n      rank:\n        type: enum\n        label: Rank\n        options: [associate, professor]\n      tenured:\n        type: boolean\n        label: Tenured\n      start_year:\n        type: range\n        label: Start year\n        min: 1820\n        max: 1880\n  queries:\n    path: collections/queries\n",
