    "theme.yml": "# Theme — \"Institute\" (academic-metrics default)\n#\n# Clean, institutional palette suited to administrative reporting:\n# near-white page, slate body text, Inter throughout for a legible,\n# spreadsheet-adjacent feel. Semantic tokens drive every surface so a\n# site author overrides colors and fonts once and the whole report —\n# preview AND downloaded xlsx typography, once the style pack reads\n# these vars at compile time — tracks the change.\n#\n# Tenant-level tuning:\n#   - `colors.primary` sets the link/button hue (currently blue).\n#   - `colors.accent` drives totals rows, chart highlights, emphasis.\n#   - `fonts.heading` / `fonts.body` flow through to Excel's font table\n#     (pending the xlsx style-pack pass planned in slice 9).\n\n# ─── Colors ────────────────────────────────────────────────────────────────\ncolors:\n  primary: '#1e40af'     # Institutional blue — primary actions, links\n  secondary: '#475569'   # Slate — secondary surfaces, table borders\n  accent: '#be123c'      # Rose — totals rows, emphasis\n  neutral: slate\n\n# ─── Page background ────────────────────────────────────────────────────────\nbackground: '#fafbfc'\n\n# ─── Fonts ──────────────────────────────────────────────────────────────────\nfonts:\n  heading: \"'Inter', ui-sans-serif, system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif\"\n  body: \"'Inter', ui-sans-serif, system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif\"\n  mono: \"'JetBrains Mono', ui-monospace, SFMono-Regular, Menlo, monospace\"\n  import:\n    - url: https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap\n    - url: https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500&display=swap\n\n# ─── Context overrides ──────────────────────────────────────────────────────\ncontexts:\n  light:\n    section: '#fafbfc'\n    card: '#ffffff'\n    heading: '#0f172a'\n    body: '#334155'\n    subtle: '#64748b'\n    border: '#e2e8f0'\n    muted: '#f1f5f9'\n  medium:\n    section: '#f1f5f9'\n    card: '#ffffff'\n    heading: '#0f172a'\n    body: '#334155'\n    subtle: '#64748b'\n    border: '#cbd5e1'\n    muted: '#e2e8f0'\n  dark:\n    section: '#0f172a'\n    card: '#1e293b'\n    heading: '#f8fafc'\n    body: '#e2e8f0'\n    subtle: '#94a3b8'\n    border: '#334155'\n    muted: '#1e293b'\n\n# ─── Inline styles ──────────────────────────────────────────────────────────\ninline:\n  accent:\n    color: 'var(--accent)'\n    font-weight: '600'\n  subtle:\n    color: 'var(--subtle)'\n    font-style: italic\n",
